CREATE TABLE `ventas` (
  `id` int NOT NULL AUTO_INCREMENT,
  `numero_venta` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `mla_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `canal` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `nombre_cliente` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `telefono_cliente` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `dni_cliente` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'DNI/CUIT del cliente',
  `provincia_cliente` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT 'Capital Federal' COMMENT 'Provincia del cliente',
  `fecha_venta` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `fecha_entrega_estimada` date DEFAULT NULL,
  `fecha_entrega_real` datetime DEFAULT NULL,
  `importe_total` decimal(10,2) NOT NULL,
  `importe_abonado` decimal(10,2) DEFAULT '0.00',
  `metodo_pago` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `tipo_entrega` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `metodo_envio` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `ubicacion_despacho` enum('DEP','FULL') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'DEP' COMMENT 'Ubicación desde donde se despachará (DEP=Depósito propio, FULL=Full ML)',
  `zona_envio` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `direccion_entrega` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `responsable_entrega` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `estado_pago` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'pendiente',
  `fecha_modificacion` timestamp NULL DEFAULT NULL,
  `fecha_entrega` datetime DEFAULT NULL,
  `estado_entrega` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'pendiente',
  `stock_descontado` tinyint(1) DEFAULT '0',
  `fecha_descuento_stock` datetime DEFAULT NULL,
  `notas` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `usuario_registro` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `fecha_registro` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `estado` enum('ACTIVA','EN_PROCESO','ENTREGADA','CANCELADA') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'ACTIVA',
  `costo_flete` decimal(10,2) DEFAULT '0.00',
  `pago_mercadopago` decimal(10,2) DEFAULT '0.00',
  `pago_efectivo` decimal(10,2) DEFAULT '0.00',
  `factura_business_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Razón social de ML',
  `factura_doc_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Tipo de documento',
  `factura_doc_number` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Número de documento/CUIT',
  `factura_taxpayer_type` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Tipo de contribuyente IVA',
  `factura_city` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Ciudad de facturación',
  `factura_street` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Dirección de facturación',
  `factura_state` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Provincia de facturación',
  `factura_zip_code` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Código postal',
  `factura_generada` tinyint(1) DEFAULT '0' COMMENT 'Si ya se generó el Excel de facturación',
  `factura_fecha_generacion` datetime DEFAULT NULL COMMENT 'Fecha de generación del Excel',
  PRIMARY KEY (`id`),
  UNIQUE KEY `numero_venta` (`numero_venta`)
) ENGINE=InnoDB AUTO_INCREMENT=172 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
