TOCK' else 'DISPONIBLE' end) AS `estado_stock` from `productos_base` `pb` union all select `pc`.`id` AS `id`,`pc`.`sku` AS `sku`,(case when (`pc`.`nombre` like '%200x200%') then trim(replace(`pc`.`nombre`,'200x200','')) when (`pc`.`nombre` like '%180x200%') then trim(replace(`pc`.`nombre`,'180x200','')) when (`pc`.`nombre` like '%160x200%') then trim(replace(`pc`.`nombre`,'160x200','')) when (`pc`.`nombre` like '%100x200%') then trim(replace(`pc`.`nombre`,'100x200','')) when (`pc`.`nombre` like '%90x200%') then trim(replace(`pc`.`nombre`,'90x200','')) when (`pc`.`nombre` like '%80x200%') then trim(replace(`pc`.`nombre`,'80x200','')) when (`pc`.`nombre` like '%150x190%') then trim(replace(`pc`.`nombre`,'150x190','')) when (`pc`.`nombre` like '%140x190%') then trim(replace(`pc`.`nombre`,'140x190','')) when (`pc`.`nombre` like '%100x190%') then trim(replace(`pc`.`nombre`,'100x190','')) when (`pc`.`nombre` like '%90x190%') then trim(replace(`pc`.`nombre`,'90x190','')) when (`pc`.`nombre` like '%80x190%') then trim(replace(`pc`.`nombre`,'80x190','')) else `pc`.`nombre` end) AS `nombre`,(case when (`pc`.`nombre` like '%200x200%') then '200x200' when (`pc`.`nombre` like '%180x200%') then '180x200' when (`pc`.`nombre` like '%160x200%') then '160x200' when (`pc`.`nombre` like '%100x200%') then '100x200' when (`pc`.`nombre` like '%90x200%') then '90x200' when (`pc`.`nombre` like '%80x200%') then '80x200' when (`pc`.`nombre` like '%150x190%') then '150x190' when (`pc`.`nombre` like '%140x190%') then '140x190' when (`pc`.`nombre` like '%100x190%') then '100x190' when (`pc`.`nombre` like '%90x190%') then '90x190' when (`pc`.`nombre` like '%80x190%') then '80x190' else NULL end) AS `medida`,(case when (`pc`.`sku` like 'S%') then 'sommier' when (`pc`.`sku` like 'C%') then 'colchon' else 'almohada' end) AS `tipo`,NULL AS `stock_fisico`,0 AS `stock_comprometido`,`sc`.`stock_disponible` AS `stock_disponible`,0 AS `stock_minimo_pausar`,1 AS `stock_minimo_reactivar`,'COMPUESTO' AS `tipo_producto`,NULL AS `modelo`,(case when (`sc`.`stock_disponible` <= 0) then 'SIN_STOCK' else 'DISPONIBLE' end) AS `estado_stock` from (`productos_compuestos` `pc` join `stock_compuestos` `sc` on((`pc`.`id` = `sc`.`producto_compuesto_id`))) */;
